import AppKit
import Carbon

// Namespace: LEX!
private let toggle_input_mode_hot_key_id = EventHotKeyID(signature: OSType(0x4C455821), id: 1)
// Tag: LEX!
private let synthetic_event_source_user_data: Int64 = 0x4C455821

@main
struct LexApp {
    static func main() {
        let application = NSApplication.shared

        let app_delegate = AppDelegate()
        application.delegate = app_delegate

        // Start as MenuBar app.
        // Info.plist already has LSUIElement=true. This is a fallback if
        // the app is launched without that bundle setting.
        application.setActivationPolicy(.accessory)

        application.run()
    }
}

private enum InputMode {
    case literal, telex
}

private class LexEngine {
    private var state: UnsafeMutableRawPointer?

    func initialize() {}

    func destroy() {}

    func reset() {}

    func type() {}

    func backspace() {}

    func buffer_full() {}

    func buffer_empty() {}

    func buffer_effective_full() {}

    func synthetic_backspaces() {}

    func compose_replacement() -> (buffer: [UInt16], count: UInt8) {}
}

private final class AppDelegate: NSObject, NSApplicationDelegate {
    private var status_item: NSStatusItem?
    private var telex_image: NSImage? = {
        let image = NSImage(
            systemSymbolName: "pencil",
            accessibilityDescription: "Lex"
        )
        image?.isTemplate = true
        return image
    }()
    private var literal_image: NSImage? = {
        let image = NSImage(
            systemSymbolName: "pencil.slash",
            accessibilityDescription: "Lex"
        )
        image?.isTemplate = true
        return image
    }()
    private var telex_sound: NSSound? = NSSound(named: "Pop")
    private var literal_sound: NSSound? = NSSound(named: "Tink")

    private var engine_state: UnsafeMutableRawPointer?
    private var replacement_buffer: [UInt16] = [UInt16](
        repeating: 0,
        count: Int(lex_replacement_buffer_length)
    )
    private var replacement_count: UInt8 = 0
    private var signal_sources: [DispatchSourceSignal] = []
    private var input_mode: InputMode = .telex
    private var toggle_input_mode_event_handler_ref: EventHandlerRef?
    private var toggle_input_mode_hot_key_ref: EventHotKeyRef?
    private var toggle_input_mode_sound: NSSound?

    private var event_tap: CFMachPort?
    private var event_tap_run_loop_source: CFRunLoopSource?
    private var synthetic_event_source: CGEventSource?

    func applicationDidFinishLaunching(_ notification: Notification) {
        print("Activated.")
        initialize_status_item()
        install_signal_handler(SIGINT)
        install_signal_handler(SIGTERM)
        initialize_engine_state()
        initialize_synthetic_event_source()
        start_event_tap()
        register_toggle_input_mode_hot_key()
    }

    func applicationWillTerminate(_ notification: Notification) {
        print("Shutting down...")
        unregister_toggle_input_mode_hot_key()
        stop_event_tap()
        destroy_synthetic_event_source()
        destroy_engine_state()
        destroy_status_item()
        signal_sources.removeAll()
    }

    private func initialize_engine_state() {
        precondition(engine_state == nil)
        let byte_count = Int(lex_state_size)
        let alignment = Int(lex_state_alignment)
        let state = UnsafeMutableRawPointer.allocate(
            byteCount: byte_count,
            alignment: alignment
        )
        lex_init(state)
        engine_state = state
    }

    private func destroy_engine_state() {
        guard let state = engine_state else {
            return
        }
        state.deallocate()
        engine_state = nil
    }

    private func install_signal_handler(_ signal_number: Int32) {
        signal(signal_number, SIG_IGN)
        let source = DispatchSource.makeSignalSource(signal: signal_number, queue: .main)
        source.setEventHandler {
            NSApp.terminate(nil)
        }
        source.resume()
        signal_sources.append(source)
    }

    private func register_toggle_input_mode_hot_key() {
        let self_pointer = Unmanaged.passUnretained(self).toOpaque()
        var event_type = EventTypeSpec(eventClass: OSType(kEventClassKeyboard), eventKind: UInt32(kEventHotKeyPressed))
        InstallEventHandler(
            GetApplicationEventTarget(),
            { _, event, userData -> OSStatus in
                guard let userData else {
                    return OSStatus(eventNotHandledErr)
                }
                var hot_key_id = EventHotKeyID()
                GetEventParameter(
                    event!,
                    EventParamName(kEventParamDirectObject),
                    EventParamType(typeEventHotKeyID),
                    nil,
                    MemoryLayout<EventHotKeyID>.size,
                    nil,
                    &hot_key_id
                )
                if hot_key_id.signature == toggle_input_mode_hot_key_id.signature &&
                        hot_key_id.id == toggle_input_mode_hot_key_id.id {
                    let app_delegate = Unmanaged<AppDelegate>
                        .fromOpaque(userData)
                        .takeUnretainedValue()
                    DispatchQueue.main.async {
                        app_delegate.toggle_input_mode()
                    }
                }
                return noErr
            },
            1,
            &event_type,
            self_pointer,
            &toggle_input_mode_event_handler_ref
        )
        let id = toggle_input_mode_hot_key_id
        RegisterEventHotKey(
            UInt32(kVK_Space),
            UInt32(controlKey | optionKey),
            id,
            GetApplicationEventTarget(),
            0,
            &toggle_input_mode_hot_key_ref
        )
    }

    private func unregister_toggle_input_mode_hot_key() {
        guard let toggle_input_mode_hot_key_ref else {
            return
        }
        UnregisterEventHotKey(toggle_input_mode_hot_key_ref)
        self.toggle_input_mode_hot_key_ref = nil

        guard let toggle_input_mode_event_handler_ref else {
            return
        }
        RemoveEventHandler(toggle_input_mode_event_handler_ref)
        self.toggle_input_mode_event_handler_ref = nil
    }

    private func toggle_input_mode() {
        // Change mode.
        input_mode = input_mode == .telex ? .literal : .telex
        status_item?.button?.image = input_mode == .telex ? telex_image : literal_image
        // Reset state.
        lex_init(engine_state)
        // Play sound when toggling mode.
        toggle_input_mode_sound?.stop()
        toggle_input_mode_sound = input_mode == .telex ? telex_sound : literal_sound
        toggle_input_mode_sound?.play()
    }

    private func start_event_tap() {
        precondition(event_tap == nil)
        precondition(event_tap_run_loop_source == nil)

        let options = [ kAXTrustedCheckOptionPrompt.takeUnretainedValue(): true ] as CFDictionary
        guard AXIsProcessTrustedWithOptions(options) else {
            print("Accessibility permission required. Grant access in System Settings > Privacy & Security > Accessibility, then relaunch.")
            return
        }

        // TODO: we must understand the mask.
        // let event_mask = (1 << CGEventType.keyDown.rawValue
        //         | 1 << CGEventType.tapDisabledByTimeout.rawValue
        //         | 1 << CGEventType.tapDisabledByUserInput.rawValue)
        let event_mask =
            (CGEventMask(1) << CGEventType.keyDown.rawValue)
            | (CGEventMask(1) << CGEventType.flagsChanged.rawValue)
            | (CGEventMask(1) << CGEventType.leftMouseDown.rawValue)
            | (CGEventMask(1) << CGEventType.rightMouseDown.rawValue)
            | (CGEventMask(1) << CGEventType.tapDisabledByTimeout.rawValue)
            | (CGEventMask(1) << CGEventType.tapDisabledByUserInput.rawValue)
        let self_pointer = Unmanaged.passUnretained(self).toOpaque()
        guard let tap = CGEvent.tapCreate(
            tap: .cgSessionEventTap,
            place: .headInsertEventTap,
            options: .defaultTap,
            eventsOfInterest: CGEventMask(event_mask),

            callback: event_tap_callback,
            userInfo: self_pointer
        ) else {
            print("Failed to create event tap.")
            return
        }
        let run_loop_source = CFMachPortCreateRunLoopSource(kCFAllocatorDefault, tap, 0)
        event_tap = tap
        event_tap_run_loop_source = run_loop_source
        CFRunLoopAddSource(CFRunLoopGetCurrent(), run_loop_source, .commonModes)
        CGEvent.tapEnable(tap: tap, enable: true)
        print("Event tap started.")
    }

    private func stop_event_tap() {
        guard let tap = event_tap else {
            return
        }
        CGEvent.tapEnable(tap: tap, enable: false)
        if let run_loop_source = event_tap_run_loop_source {
            CFRunLoopRemoveSource(CFRunLoopGetCurrent(), run_loop_source, .commonModes)
        }
        CFMachPortInvalidate(tap)
        event_tap_run_loop_source = nil
        event_tap = nil
        print("Event tap stopped.")
    }

    private func initialize_synthetic_event_source() {
        precondition(synthetic_event_source == nil)
        let source = CGEventSource(stateID: .privateState)
        source?.userData = synthetic_event_source_user_data
        synthetic_event_source = source
    }

    private func destroy_synthetic_event_source() {
        synthetic_event_source = nil
    }

    private func initialize_status_item() {
        precondition(status_item == nil)

        let status_item = NSStatusBar.system.statusItem(
            withLength: NSStatusItem.squareLength
        )
        self.status_item = status_item

        let menu = NSMenu()

        let lock_item = NSMenuItem(
            title: "Lock keyboard",
            action: #selector(lock_keyboard(_:)),
            keyEquivalent: ""
        )
        lock_item.target = self
        menu.addItem(lock_item)

        menu.addItem(.separator())

        let quit_item = NSMenuItem(
            title: "Quit",
            action: #selector(quit(_:)),
            keyEquivalent: "q"
        )
        quit_item.target = self
        menu.addItem(quit_item)

        status_item.menu = menu
        status_item.button?.image = input_mode == .telex ? telex_image : literal_image
    }

    private func destroy_status_item() {
        guard let status_item else {
            return
        }

        NSStatusBar.system.removeStatusItem(status_item)
        self.status_item = nil
    }

    @objc
    private func lock_keyboard(_ sender: Any?) {
        // Preserve current behavior: current SwiftUI "Lock inputs" button is a no-op.
        // If desired later, this can call toggle_input_mode().
    }

    @objc
    private func quit(_ sender: Any?) {
       NSApp.terminate(nil) 
    }

    func get_synthetic_event_source() -> CGEventSource? {
        return synthetic_event_source
    }

    func enable_event_tap() {
        // TODO: why do we need to re-enable the tap?
        guard let event_tap else {
            return
        }
        CGEvent.tapEnable(tap: event_tap, enable: true)
    }

    func type_character(character: UInt8) {
        lex_add(engine_state, character)
    }

    func type_backspace() {
        if !lex_buffer_empty(engine_state) {
            // Call backspace action to keep buffer in sync with real input.
            lex_backspace(engine_state)
        }
    }

    func reset_engine_state() {
        lex_init(engine_state)
    }

    func is_buffer_full() -> Bool {
        return lex_buffer_full(engine_state)
    }

    func is_buffer_effective_full() -> Bool {
        return lex_buffer_effective_full(engine_state)
    }

    func is_literal() -> Bool {
        return input_mode == .literal
    }

    func calculate_synthetic_backspaces() -> UInt8 {
        return lex_calculate_synthetic_backspaces(engine_state)
    }

    func compose_replacement() {
        lex_compose_utf16_string_replacement(
            engine_state,
            &replacement_buffer,
            &replacement_count
        )
    }

    func get_replacement_buffer() -> [UInt16] {
        return replacement_buffer
    }

    func get_replacement_count() -> UInt8 {
        return replacement_count
    }
}

private func event_tap_callback(
    proxy: CGEventTapProxy,
    type event_type: CGEventType,
    event: CGEvent,
    userInfo: UnsafeMutableRawPointer?
) -> Unmanaged<CGEvent>? {
    // passthrough event when the event tap is inactive.
    guard let userInfo else {
        return Unmanaged.passUnretained(event)
    }

    let app_delegate = Unmanaged<AppDelegate>
            .fromOpaque(userInfo)
            .takeUnretainedValue()

    switch event_type {
        case .tapDisabledByTimeout, .tapDisabledByUserInput:
            // Reset engine.
            app_delegate.reset_engine_state()
            // Re-enable tap.
            app_delegate.enable_event_tap()
            // Pass through event.
            return Unmanaged.passUnretained(event)

        case .leftMouseDown, .rightMouseDown:
            // Reset engine.
            app_delegate.reset_engine_state()
            // Pass through event.
            return Unmanaged.passUnretained(event)

        case .flagsChanged:
            // Pass through event.
            // Don't reset for plain Shift / Caps Lock.
            return Unmanaged.passUnretained(event)

        case .keyDown:
            // Handle key down.

            // Ignore Lex's synthetic events.
            if event.getIntegerValueField(.eventSourceUserData) == synthetic_event_source_user_data {
                return Unmanaged.passUnretained(event)
            }

            // passthrough event when in literal mode.
            if app_delegate.is_literal() {
                return Unmanaged.passUnretained(event)
            }

            // Get keycode to detect special key pressed.
            let key_code = event.getIntegerValueField(.keyboardEventKeycode)
            switch key_code {
                case Int64(kVK_Delete):
                    // User input backspace.
                    // Call backspace action to keep buffer in sync with real input.
                    app_delegate.type_backspace()
                    // Passthrough backspace.
                    return Unmanaged.passUnretained(event)

                default:
                        // Reset state for unhandled keycode.
                        // lex_init(state)
                        // return Unmanaged.passUnretained(event)
                        break
            }

            // Detect and handle alphabetic input.
            var character_count = 0
                event.keyboardGetUnicodeString(
                        maxStringLength: 0,
                        actualStringLength: &character_count,
                        unicodeString: nil
                        )
                guard character_count == 1 else {
                    // No character, could be a special key, could not handle this case.
                    app_delegate.reset_engine_state()
                        return Unmanaged.passUnretained(event)
                }

            // Get Unicode character.
            var character: UniChar = 0
                event.keyboardGetUnicodeString(
                        maxStringLength: 1,
                        actualStringLength: &character_count,
                        unicodeString: &character
                        )
                // Check if it's alphabetic.
                let is_alphabetic = (character >= 65 && character <= 90)
                || (character >= 97 && character <= 122)
                guard is_alphabetic else {
                    // No alphabitec, reset state.
                    app_delegate.reset_engine_state()
                        return Unmanaged.passUnretained(event)
                }

            // Valid input, safe to process with the engine.
            let input = UInt8(character);
            if app_delegate.is_buffer_full() {
                // The state reach the limit, reset it before continue processing.
                app_delegate.reset_engine_state()
            }

            if app_delegate.is_buffer_effective_full() {
                // The buffer effective is full, process literal input.
                app_delegate.type_character(character: input)
                return Unmanaged.passUnretained(event)
            } else {
                // The buffer effective has room, process with synthetic backspace and replacement.
                guard let synthetic_event_source = app_delegate.get_synthetic_event_source() else {
                    // No event source to send synthetic event.
                    app_delegate.reset_engine_state()
                    return Unmanaged.passUnretained(event)
                }

                // Send the input character to engine.
                app_delegate.type_character(character: input)

                // Calculate synthetic backspaces.
                let backspace_count = app_delegate.calculate_synthetic_backspaces()

                // Post synthetic backspaces to event tap.
                if backspace_count > 0 {
                    for _ in 0..<backspace_count {
                        if let synthetic_backspace_down = CGEvent(
                            keyboardEventSource: synthetic_event_source,
                            virtualKey: CGKeyCode(kVK_Delete),
                            keyDown: true
                        ) {
                            synthetic_backspace_down.tapPostEvent(proxy)
                        }


                        if let synthetic_backspace_up = CGEvent(
                            keyboardEventSource: synthetic_event_source,
                            virtualKey: CGKeyCode(kVK_Delete),
                            keyDown: false
                        ) {
                            synthetic_backspace_up.tapPostEvent(proxy)
                        }
                    }
                }

                // Compose replacement.
                app_delegate.compose_replacement()
                let replacement_buffer = app_delegate.get_replacement_buffer()
                let replacement_count = app_delegate.get_replacement_count()

                // Post replacement to event tap.
                if replacement_count > 0 {
                    var replacement_characters = Array(replacement_buffer[0..<Int(replacement_count)])

                    if let synthetic_characters_down = CGEvent(
                        keyboardEventSource: synthetic_event_source,
                        virtualKey: 0,
                        keyDown: true
                    ) {
                        synthetic_characters_down.keyboardSetUnicodeString(
                            stringLength: replacement_characters.count,
                            unicodeString: &replacement_characters
                        )
                        synthetic_characters_down.tapPostEvent(proxy)
                    }


                    if let synthetic_characters_up = CGEvent(
                        keyboardEventSource: synthetic_event_source,
                        virtualKey: 0,
                        keyDown: false
                    ) {
                        synthetic_characters_up.keyboardSetUnicodeString(
                            stringLength: replacement_characters.count,
                            unicodeString: &replacement_characters
                        )
                        synthetic_characters_up.tapPostEvent(proxy)
                    }
                }
                return nil
            }


        default:
            return Unmanaged.passUnretained(event)
    }
}

#ifndef LEX_H
#define LEX_H

#include <stdbool.h>
#include <stddef.h>
#include <stdint.h>

#ifdef __cplusplus
extern "C" {
#endif

// Required allocation size of the engine state, in bytes.
extern const size_t lex_state_size;

// Required allocation alignment of the engine state, in bytes.
extern const size_t lex_state_alignment;

// Initialize a state buffer. The buffer must be at least `lex_state_size`
// bytes and aligned to `lex_state_alignment`.
void lex_init(void *state);

// Feed one ASCII alphabetic character (a-zA-Z) into the engine.
void lex_add(void *state, uint8_t c);

// Apply a single backspace to the engine state.
void lex_backspace(void *state);

uint8_t lex_calculate_synthetic_backspaces(void *state);

bool lex_buffer_effective_full(void *state);

// Indicate the buffer_length is at the maximum limit.
bool lex_buffer_full(void *state);

// Indicate the buffer_length is zero.
bool lex_buffer_empty(void *state);

extern const size_t lex_replacement_buffer_length;

// `replacement_buffer` capacity must be exactly `lex_replacement_buffer_length`.
void lex_compose_utf16_string_replacement(
    void *state,
    uint16_t *replacement_buffer,
    uint8_t *replacement_count);

#ifdef __cplusplus
}
#endif

#endif // LEX_H

const std = @import("std");

const assert = std.debug.assert;
const expectEqual = std.testing.expectEqual;
const indexOfScalar = std.mem.indexOfScalar;
const isAlphabetic = std.ascii.isAlphabetic;
const maxInt = std.math.maxInt;
const toUpper = std.ascii.toUpper;

const Diacritic = enum(u8) {
    empty, // nguyên âm, không dấu.
    circumflex, // dấu nón: â, ô, ê.
    horn, // dấu móc: ư, ơ.
    breve, // dấu ă.
    stroke, // dấu gạch: đ.
};

const Tone = enum(u8) {
    level, // thanh ngang, không dấu.
    rising, // sắc.
    falling, // huyền.
    dipping_rising, // hỏi.
    rising_glottalized, // ngã.
    falling_glottalized, // nặng.
};

const Span = struct {
    // Alphabet ASCII character, could be lowercase or uppercase.
    base: u8,
    // By default, it's plain alphabet character.
    diacritic: Diacritic = .empty,
    // By default, no tone is placed.
    tone: Tone = .level,

    // Create a Span with plain alphabet character, no diacritic, no tone.
    fn init(base: u8) Span {
        return Span.init_diacritic_tone(base, .empty, .level);
    }

    // Create a Span with diacritic, no tone.
    fn init_diacritic(base: u8, diacritic: Diacritic) Span {
        return Span.init_diacritic_tone(base, diacritic, .level);
    }

    fn init_diacritic_tone(base: u8, diacritic: Diacritic, tone: Tone) Span {
        // Only allow a-zA-Z.
        assert(isAlphabetic(base));

        // Only allow a valid Vietnamese alphabet combinations.
        switch (diacritic) {
            // All alphabet is allowed without diacritic.
            .empty => {},
            // Only a, o, e are valid with circumflex.
            .circumflex => switch (base) {
                'A', 'E', 'O', 'a', 'e', 'o' => {},
                else => unreachable,
            },
            // Only u, o are valid with horn.
            .horn => switch (base) {
                'O', 'U', 'o', 'u' => {},
                else => unreachable,
            },
            // Only a is valid with breve.
            .breve => switch (base) {
                'A', 'a' => {},
                else => unreachable,
            },
            // Only d is valid with stroke.
            .stroke => switch (base) {
                'D', 'd' => {},
                else => unreachable,
            },
        }

        // Only allow tone on valid Vietnamese vowels based on Vietnamese rules.
        switch (tone) {
            // All alphabet is allowed with level.
            .level => {},
            // All vowels is allowed with remaining tones.
            .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized => switch (base) {
                'A', 'E', 'I', 'O', 'U', 'Y', 'a', 'e', 'i', 'o', 'u', 'y' => {},
                else => unreachable,
            },
        }

        return .{ .base = base, .diacritic = diacritic, .tone = tone };
    }

    // Compare only base character, ignore case and other aspects.
    fn equals_ignore_case_diacritic_tone(self: *const Span, base: u8) bool {
        // Base must be alphabet letters.
        assert(isAlphabetic(base));

        return toUpper(self.base) == toUpper(base);
    }

    // Compare the span with a base character (ignore case) and diacritic, tone is ignored.
    fn equals_ignore_case_tone(self: *const Span, base: u8, diacritic: Diacritic) bool {
        // Base must be alphabet letters.
        assert(isAlphabetic(base));

        return toUpper(self.base) == toUpper(base) and self.diacritic == diacritic;
    }

    // Compare the Span base (ignore case), diacritic, tone.
    fn equals_ignore_case(self: *const Span, base: u8, diacritic: Diacritic, tone: Tone) bool {
        // Base must be alphabet letters.
        assert(isAlphabetic(base));

        return toUpper(self.base) == toUpper(base) and self.diacritic == diacritic and self.tone == tone;
    }

    // Check if the Span.base is vowel or not.
    fn is_vowel(self: *const Span) bool {
        return switch (toUpper(self.base)) {
            'A', 'E', 'I', 'O', 'U', 'Y' => true,
            else => false,
        };
    }

    // Check if the Span.base is consonant or not.
    fn is_consonant(self: *const Span) bool {
        return !self.is_vowel();
    }

    fn to_utf16(self: *const Span) u16 {
        assert(isAlphabetic(self.base));

        // fast path, plain alphabet.
        if (self.diacritic == .empty and self.tone == .level) {
            return self.base;
        }

        switch (self.base) {
            'a' => {
                switch (self.diacritic) {
                    .empty => {
                        switch (self.tone) {
                            .level => unreachable,
                            .rising => return 0x00E1, // á.
                            .falling => return 0x00E0, // à.
                            .dipping_rising => return 0x1EA3, // ả.
                            .rising_glottalized => return 0x00E3, // ã.
                            .falling_glottalized => return 0x1EA1, // ạ.
                        }
                    },
                    .breve => {
                        switch (self.tone) {
                            .level => return 0x0103, // ă.
                            .rising => return 0x1EAF, // ắ.
                            .falling => return 0x1EB1, // ằ.
                            .dipping_rising => return 0x1EB3, // ẳ.
                            .rising_glottalized => return 0x1EB5, // ẵ.
                            .falling_glottalized => return 0x1EB7, // ặ.
                        }
                    },
                    .circumflex => {
                        switch (self.tone) {
                            .level => return 0x00E2, // â.
                            .rising => return 0x1EA5, // ấ.
                            .falling => return 0x1EA7, // ầ.
                            .dipping_rising => return 0x1EA9, // ẩ.
                            .rising_glottalized => return 0x1EAB, // ẫ.
                            .falling_glottalized => return 0x1EAD, // ậ.
                        }
                    },
                    .horn, .stroke => unreachable,
                }
            },
            'A' => {
                switch (self.diacritic) {
                    .empty => {
                        switch (self.tone) {
                            .level => unreachable,
                            .rising => return 0x00C1, // Á.
                            .falling => return 0x00C0, // À.
                            .dipping_rising => return 0x1EA2, // Ả.
                            .rising_glottalized => return 0x00C3, // Ã.
                            .falling_glottalized => return 0x1EA0, // Ạ.
                        }
                    },
                    .breve => {
